mapper.select:
SELECT * FROM esb_request_log


        AND service_name = #{serviceName}


        AND request_time >= #{startTime}


        AND request_time <= #{endTime}


        AND response_status = #{statusCd}


        AND (request_id LIKE CONCAT('%', #{keyword}, '%')
             OR request_url LIKE CONCAT('%', #{keyword}, '%')
             OR error_message LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY request_time DESC
